  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD ? BASE_PREMIUMS[item.type] * HIGH_ENCH_RATE : 0;

const highEnchantmentSurchargeFor = (items: Item[]): number =>
  sum(items.map(highEnchantmentSurchargeForItem));

